// src/utils/getPartnerFeeBps.ts
function getPartnerFeeBps(partnerFee) {
  if (!partnerFee) {
    return void 0;
  }
  if ("volumeBps" in partnerFee) {
    return partnerFee.volumeBps;
  }
  if (Array.isArray(partnerFee)) {
    for (const fee of partnerFee) {
      if ("volumeBps" in fee) {
        return fee.volumeBps;
      }
    }
  }
  return void 0;
}

// src/utils/slippage.ts
var SCALE = 10n ** 6n;
function getSlippagePercent(params) {
  const { sellAmountBeforeNetworkCosts, sellAmountAfterNetworkCosts, slippage, isSell } = params;
  const sellAmount = isSell ? sellAmountAfterNetworkCosts : sellAmountBeforeNetworkCosts;
  if (sellAmount <= 0n) {
    throw new Error("sellAmount must be greater than 0: " + sellAmount);
  }
  if (slippage < 0n) {
    throw new Error("slippage must be non-negative: " + slippage);
  }
  if (isSell) {
    const percentageInScale = SCALE - SCALE * (sellAmount - slippage) / sellAmount;
    return Number(percentageInScale) / Number(SCALE);
  } else {
    const percentageInScale = SCALE * (sellAmount + slippage) / sellAmount - SCALE;
    return Number(percentageInScale) / Number(SCALE);
  }
}
function getDefaultSlippageBps(chainId, isEthFlow) {
  if (isEthFlow) {
    return ETH_FLOW_DEFAULT_SLIPPAGE_BPS[chainId];
  } else {
    return DEFAULT_SLIPPAGE_BPS;
  }
}

// src/utils/order.ts
function getOrderDeadlineFromNow(validFor) {
  return BigInt(Math.floor(Date.now() / 1e3) + validFor);
}
function unsignedOrderForSigning(order) {
  return {
    ...order,
    sellTokenBalance: order.sellTokenBalance,
    buyTokenBalance: order.buyTokenBalance
  };
}

// src/getOrderToSign.ts
function getOrderToSign({
  chainId,
  from,
  networkCostsAmount = "0",
  isEthFlow,
  applyCostsSlippageAndFees = true,
  protocolFeeBps
}, limitOrderParams, appDataKeccak256) {
  const {
    sellAmount,
    buyAmount,
    sellToken,
    buyToken,
    kind,
    partiallyFillable = false,
    slippageBps = getDefaultSlippageBps(chainId, isEthFlow),
    partnerFee,
    validFor = DEFAULT_QUOTE_VALIDITY
  } = limitOrderParams;
  const receiver = limitOrderParams.receiver || from;
  const validTo = limitOrderParams.validTo || Number(getOrderDeadlineFromNow(validFor));
  const orderParams = {
    sellToken,
    buyToken,
    sellAmount,
    buyAmount,
    receiver,
    validTo,
    kind,
    feeAmount: networkCostsAmount,
    appData: appDataKeccak256,
    partiallyFillable
  };
  let sellAmountToUse = sellAmount;
  let buyAmountToUse = buyAmount;
  if (applyCostsSlippageAndFees) {
    const { isSell, beforeAllFees, afterSlippage } = getQuoteAmountsAndCosts({
      orderParams,
      slippagePercentBps: slippageBps,
      partnerFeeBps: getPartnerFeeBps(partnerFee),
      protocolFeeBps
    });
    sellAmountToUse = isSell ? beforeAllFees.sellAmount.toString() : afterSlippage.sellAmount.toString();
    buyAmountToUse = isSell ? afterSlippage.buyAmount.toString() : beforeAllFees.buyAmount.toString();
  }
  return {
    sellToken,
    buyToken,
    sellAmount: sellAmountToUse,
    buyAmount: buyAmountToUse,
    validTo,
    kind,
    partiallyFillable,
    appData: appDataKeccak256,
    receiver,
    feeAmount: "0",
    sellTokenBalance: SellTokenSource.ERC20,
    buyTokenBalance: BuyTokenDestination.ERC20
  };
}

