// src/suggestSlippageFromFee.ts
import { applyPercentage } from "@cowprotocol/sdk-common";
function suggestSlippageFromFee(params) {
  const { feeAmount, multiplyingFactorPercent } = params;
  if (feeAmount < 0n) {
    throw new Error("Fee amount must be non-negative: " + feeAmount);
  }
  if (multiplyingFactorPercent < 0) {
    throw new Error("multiplyingFactorPercent must be non-negative: " + multiplyingFactorPercent);
  }
  return applyPercentage(feeAmount, multiplyingFactorPercent);
}

// src/suggestSlippageFromVolume.ts
import { applyPercentage as applyPercentage2 } from "@cowprotocol/sdk-common";
function suggestSlippageFromVolume(params) {
  const { sellAmountBeforeNetworkCosts, sellAmountAfterNetworkCosts, isSell, slippagePercent } = params;
  const sellAmount = isSell ? sellAmountAfterNetworkCosts : sellAmountBeforeNetworkCosts;
  if (sellAmount <= 0n) {
    throw new Error("sellAmount must be greater than 0: " + sellAmount);
  }
  if (slippagePercent < 0) {
    throw new Error("slippagePercent must be non-negative: " + slippagePercent);
  }
  return applyPercentage2(sellAmount, slippagePercent);
}

// src/suggestSlippageBps.ts
var MAX_SLIPPAGE_BPS = 1e4;
var SLIPPAGE_FEE_MULTIPLIER_PERCENT = 50;
var SLIPPAGE_VOLUME_MULTIPLIER_PERCENT = 0.5;
function suggestSlippageBps(params) {
  const { quote, trader, isEthFlow, volumeMultiplierPercent = SLIPPAGE_VOLUME_MULTIPLIER_PERCENT } = params;
  const isSell = quote.quote.kind === OrderKind.SELL;
  const {
    beforeNetworkCosts: { sellAmount: sellAmountBeforeNetworkCosts },
    afterNetworkCosts: { sellAmount: sellAmountAfterNetworkCosts }
  } = getQuoteAmountsAndCosts2({
    orderParams: quote.quote,
    protocolFeeBps: quote.protocolFeeBps ? Number(quote.protocolFeeBps) : 0,
    partnerFeeBps: void 0,
    slippagePercentBps: 0
  });
  const { feeAmount: feeAmountString } = quote.quote;
  const feeAmount = BigInt(feeAmountString);
  const slippageBpsFromFee = suggestSlippageFromFee({
    feeAmount,
    multiplyingFactorPercent: SLIPPAGE_FEE_MULTIPLIER_PERCENT
  });
  const slippageBpsFromVolume = suggestSlippageFromVolume({
    isSell,
    sellAmountBeforeNetworkCosts,
    sellAmountAfterNetworkCosts,
    slippagePercent: volumeMultiplierPercent
  });
  const totalSlippageBps = slippageBpsFromFee + slippageBpsFromVolume;
  const slippagePercent = getSlippagePercent({
    isSell,
    sellAmountBeforeNetworkCosts,
    sellAmountAfterNetworkCosts,
    slippage: totalSlippageBps
  });
  const slippageBps = percentageToBps(slippagePercent);
  const lowerCap = isEthFlow ? ETH_FLOW_DEFAULT_SLIPPAGE_BPS[trader.chainId] : 0;
  return Math.max(Math.min(slippageBps, MAX_SLIPPAGE_BPS), lowerCap);
}

// src/resolveSlippageSuggestion.ts
async function resolveSlippageSuggestion(chainId, tradeParameters, trader, quote, isEthFlow, advancedSettings) {
  const suggestSlippageParams = {
    isEthFlow,
    quote,
    tradeParameters,
    trader,
    advancedSettings
  };
  const getSlippageSuggestion = advancedSettings?.getSlippageSuggestion;
  const priceQuality = advancedSettings?.quoteRequest?.priceQuality ?? PriceQuality.OPTIMAL;
  const defaultSuggestion = suggestSlippageBps(suggestSlippageParams);
  if (priceQuality === PriceQuality.FAST || !getSlippageSuggestion) {
    return { slippageBps: defaultSuggestion };
  }
  const amountsAndCosts = getQuoteAmountsAndCosts3({
    orderParams: quote.quote,
    slippagePercentBps: 0,
    partnerFeeBps: getPartnerFeeBps(tradeParameters.partnerFee),
    protocolFeeBps: quote.protocolFeeBps ? Number(quote.protocolFeeBps) : void 0
  });
  const { isSell, beforeAllFees, afterSlippage } = amountsAndCosts;
  try {
    const suggestedSlippage = await getSlippageSuggestion({
      chainId,
      sellToken: tradeParameters.sellToken,
      buyToken: tradeParameters.buyToken,
      sellAmount: isSell ? beforeAllFees.sellAmount : afterSlippage.sellAmount,
      buyAmount: isSell ? afterSlippage.buyAmount : beforeAllFees.buyAmount
    });
    const suggestedSlippageBps = suggestedSlippage.slippageBps;
    return {
      slippageBps: suggestedSlippageBps ? suggestSlippageBps({
        ...suggestSlippageParams,
        volumeMultiplierPercent: bpsToPercentage(suggestedSlippageBps)
      }) : defaultSuggestion
    };
  } catch (e) {
    log3(`getSlippageSuggestion() error: ${e.message || String(e)}`);
    return { slippageBps: defaultSuggestion };
  }
}

